import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");

const checks = [
  {
    label: "OpenAPI source spec",
    path: "docs/openapi.yaml",
    includes: [
      "# Auto-generated by cmd/openapi-gen",
      "openapi: 3.1.0",
      "title: Yunque Agent API",
      "version: v1.0.0",
      "securitySchemes:",
    ],
  },
  {
    label: "OpenAPI generator",
    path: "cmd/openapi-gen/main.go",
    includes: [
      "go run ./cmd/openapi-gen",
      "mux.HandleFunc",
      "OpenAPI 3.1.0",
      "operationId",
      "components",
    ],
  },
  {
    label: "Makefile OpenAPI target",
    path: "Makefile",
    includes: ["openapi:", "go run ./cmd/openapi-gen", "go test ./cmd/openapi-gen"],
  },
  {
    label: "TypeScript OpenAPI generator config",
    path: "packages/yunque-client/openapi-ts.config.ts",
    includes: ["../../docs/openapi.yaml", "@hey-api/client-fetch", "@hey-api/sdk", "@hey-api/typescript"],
  },
  {
    label: "TypeScript OpenAPI regeneration script",
    path: "packages/yunque-client/scripts/generate-openapi.mjs",
    includes: ["@hey-api", "openapi-ts", "preserved", "handcrafted incremental SDK source files"],
  },
  {
    label: "OpenAPI evolution guide",
    path: "docs/OPENAPI-EVOLUTION.md",
    includes: [
      "OpenAPI spec 演化策略",
      "breaking change",
      "operationId",
      "make openapi",
      "npm run generate",
      "npm run check:incremental",
      "node scripts/check-openapi-evolution.mjs",
    ],
  },
];

let failed = false;
for (const check of checks) {
  const abs = path.join(ROOT, check.path);
  if (!fs.existsSync(abs) || !fs.statSync(abs).isFile()) {
    console.error(`OpenAPI evolution check failed: missing ${check.label}: ${check.path}`);
    failed = true;
    continue;
  }
  const text = fs.readFileSync(abs, "utf8");
  for (const token of check.includes) {
    if (!text.includes(token)) {
      console.error(`OpenAPI evolution check failed: ${check.path} missing token ${JSON.stringify(token)}`);
      failed = true;
    }
  }
}

const spec = fs.readFileSync(path.join(ROOT, "docs/openapi.yaml"), "utf8");
const pathCount = (spec.match(/^\s{4}\/[^\n:]+:/gm) ?? []).length;
if (pathCount < 300) {
  console.error(`OpenAPI evolution check failed: expected broad gateway coverage, found only ${pathCount} path entries`);
  failed = true;
}

const operationIds = [...spec.matchAll(/operationId:\s*([^\n]+)/g)].map((match) => match[1].trim());
const uniqueOperationIds = new Set(operationIds);
if (operationIds.length === 0) {
  console.error("OpenAPI evolution check failed: no operationId entries found");
  failed = true;
}
if (operationIds.length !== uniqueOperationIds.size) {
  console.error(`OpenAPI evolution check failed: duplicate operationId entries (${operationIds.length - uniqueOperationIds.size})`);
  failed = true;
}

if (failed) process.exit(1);
console.log(`OpenAPI evolution check ok: ${pathCount} paths, ${operationIds.length} unique operationIds, regeneration and SDK policy documented`);
